using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static SchoolContext CreateWithSeedData(string dbName = null)
        {
            var context = Create(dbName);
            SeedData(context);
            return context;
        }

        private static void SeedData(SchoolContext context)
        {
            var instructors = new[]
            {
                new Instructor { ID = 1, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11") },
                new Instructor { ID = 2, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06") },
                new Instructor { ID = 3, FirstMidName = "Roger", LastName = "Harui", HireDate = DateTime.Parse("1998-07-01") }
            };
            foreach (var i in instructors)
            {
                i.CourseAssignments = new List<CourseAssignment>();
            }
            context.Instructors.AddRange(instructors);

            var departments = new[]
            {
                new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 1 },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 2 },
                new Department { DepartmentID = 3, Name = "Engineering", Budget = 200000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 3 }
            };
            context.Departments.AddRange(departments);

            var courses = new[]
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 3 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4041, Title = "Macroeconomics", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = 2 }
            };
            context.Courses.AddRange(courses);

            var students = new[]
            {
                new Student { ID = 10, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
                new Student { ID = 11, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { ID = 12, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") },
                new Student { ID = 13, FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { ID = 14, FirstMidName = "Yan", LastName = "Li", EnrollmentDate = DateTime.Parse("2012-09-01") }
            };
            foreach (var s in students)
            {
                s.Enrollments = new List<Enrollment>();
            }
            context.Students.AddRange(students);

            var enrollments = new[]
            {
                new Enrollment { StudentID = 10, CourseID = 1050, Grade = Grade.A },
                new Enrollment { StudentID = 10, CourseID = 4022, Grade = Grade.C },
                new Enrollment { StudentID = 11, CourseID = 1045, Grade = Grade.B },
                new Enrollment { StudentID = 12, CourseID = 2021, Grade = Grade.B },
                new Enrollment { StudentID = 13, CourseID = 1050 }
            };
            context.Enrollments.AddRange(enrollments);

            context.SaveChanges();
        }
    }
}

