        {
            var result = _controller.Index("date_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Anand", model.First().LastName); // 2013
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Alexander", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
