{"file_text": "using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover messages from other tests (shared static queue)
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_Enqueues_Message()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
        }

        [Fact]
        public void SendNotification_WithDisplayName_IncludesInMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.Contains("John Doe", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.Contains("42", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("New Course 'Chemistry' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("Course 'Chemistry' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("Course 'Chemistry' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_SetsCreatedBy()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.Equal("Admin", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, null);

            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsIsReadFalse()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();

            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_FIFO_Order()
        {
            _service.SendNotification("First", "1", EntityOperation.CREATE);
            _service.SendNotification("Second", "2", EntityOperation.UPDATE);
            _service.SendNotification("Third", "3", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.Equal("First", first.EntityType);
            Assert.Equal("Second", second.EntityType);
            Assert.Equal("Third", third.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_MultipleMessages_AllReceivable()
        {
            for (int i = 0; i < 10; i++)
            {
                _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            int count = 0;
            while (_service.ReceiveNotification() != null)
            {
                count++;
            }

            Assert.Equal(10, count);
        }
    }
}
