{"file_text": "using System;
using System.ComponentModel.DataAnnotations;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class ModelTests
    {
        #region Person / Student / Instructor

        [Fact]
        public void Person_FullName_ConcatenatesLastAndFirst()
        {
            var student = new Student { FirstMidName = "Carson", LastName = "Alexander" };

            Assert.Equal("Alexander, Carson", student.FullName);
        }

        [Fact]
        public void Student_EnrollmentDate_IsRequired()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = default
            };

            var results = ValidateModel(student);
            Assert.Contains(results, v => v.MemberNames.Contains("EnrollmentDate"));
        }

        [Fact]
        public void Student_LastName_IsRequired()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = null,
                EnrollmentDate = DateTime.Now
            };

            var results = ValidateModel(student);
            Assert.Contains(results, v => v.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_FirstMidName_IsRequired()
        {
            var student = new Student
            {
                FirstMidName = null,
                LastName = "Test",
                EnrollmentDate = DateTime.Now
            };

            var results = ValidateModel(student);
            Assert.Contains(results, v => v.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Student_LastName_MaxLength50()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = new string('A', 51),
                EnrollmentDate = DateTime.Now
            };

            var results = ValidateModel(student);
            Assert.Contains(results, v => v.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_FirstMidName_MaxLength50()
        {
            var student = new Student
            {
                FirstMidName = new string('A', 51),
                LastName = "Test",
                EnrollmentDate = DateTime.Now
            };

            var results = ValidateModel(student);
            Assert.Contains(results, v => v.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Instructor_HireDate_IsRequired()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = default
            };

            var results = ValidateModel(instructor);
            Assert.Contains(results, v => v.MemberNames.Contains("HireDate"));
        }

        [Fact]
        public void Instructor_FullName_ConcatenatesLastAndFirst()
        {
            var instructor = new Instructor { FirstMidName = "Kim", LastName = "Abercrombie" };

            Assert.Equal("Abercrombie, Kim", instructor.FullName);
        }

        #endregion

        #region Course

        [Fact]
        public void Course_Title_MaxLength50()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = new string('A', 51),
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, v => v.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_Title_MinLength3()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "AB",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, v => v.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_Credits_RangeValidation_TooHigh()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Valid",
                Credits = 6,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, v => v.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_Credits_RangeValidation_Negative()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Valid",
                Credits = -1,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, v => v.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_Credits_ValidRange()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Valid Course",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.DoesNotContain(results, v => v.MemberNames.Contains("Credits"));
        }

        #endregion

        #region Department

        [Fact]
        public void Department_Name_MaxLength50()
        {
            var dept = new Department
            {
                Name = new string('A', 51),
                Budget = 100000,
                StartDate = DateTime.Now
            };

            var results = ValidateModel(dept);
            Assert.Contains(results, v => v.MemberNames.Contains("Name"));
        }

        [Fact]
        public void Department_Name_MinLength3()
        {
            var dept = new Department
            {
                Name = "AB",
                Budget = 100000,
                StartDate = DateTime.Now
            };

            var results = ValidateModel(dept);
            Assert.Contains(results, v => v.MemberNames.Contains("Name"));
        }

        #endregion

        #region Enrollment

        [Fact]
        public void Enrollment_Grade_CanBeNull()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1,
                StudentID = 1,
                Grade = null
            };

            var results = ValidateModel(enrollment);
            Assert.Empty(results);
        }

        [Fact]
        public void Enrollment_Grade_ValidValues()
        {
            foreach (Grade grade in Enum.GetValues(typeof(Grade)))
            {
                var enrollment = new Enrollment
                {
                    EnrollmentID = 1,
                    CourseID = 1,
                    StudentID = 1,
                    Grade = grade
                };

                var results = ValidateModel(enrollment);
                Assert.Empty(results);
            }
        }

        #endregion

        #region Notification

        [Fact]
        public void Notification_EntityType_Required()
        {
            var notification = new Notification
            {
                EntityType = null,
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test",
                CreatedAt = DateTime.Now
            };

            var results = ValidateModel(notification);
            Assert.Contains(results, v => v.MemberNames.Contains("EntityType"));
        }

        [Fact]
        public void Notification_EntityId_Required()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = null,
                Operation = "CREATE",
                Message = "Test",
                CreatedAt = DateTime.Now
            };

            var results = ValidateModel(notification);
            Assert.Contains(results, v => v.MemberNames.Contains("EntityId"));
        }

        [Fact]
        public void Notification_Operation_Required()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = null,
                Message = "Test",
                CreatedAt = DateTime.Now
            };

            var results = ValidateModel(notification);
            Assert.Contains(results, v => v.MemberNames.Contains("Operation"));
        }

        [Fact]
        public void Notification_Message_Required()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = null,
                CreatedAt = DateTime.Now
            };

            var results = ValidateModel(notification);
            Assert.Contains(results, v => v.MemberNames.Contains("Message"));
        }

        [Fact]
        public void Notification_IsRead_DefaultsFalse()
        {
            var notification = new Notification();

            Assert.False(notification.IsRead);
        }

        [Fact]
        public void Notification_ReadAt_Nullable()
        {
            var notification = new Notification();

            Assert.Null(notification.ReadAt);
        }

        #endregion

        #region OfficeAssignment

        [Fact]
        public void OfficeAssignment_Location_MaxLength50()
        {
            var office = new OfficeAssignment
            {
                InstructorID = 1,
                Location = new string('A', 51)
            };

            var results = ValidateModel(office);
            Assert.Contains(results, v => v.MemberNames.Contains("Location"));
        }

        #endregion

        #region Helper

        private static IList<ValidationResult> ValidateModel(object model)
        {
            var context = new ValidationContext(model, serviceProvider: null, items: null);
            var results = new List<ValidationResult>();
            Validator.TryValidateObject(model, context, results, true);
            return results;
        }

        #endregion
    }
}
