using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempPath;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _tempPath = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempPath);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempPath);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempPath);
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempPath))
                Directory.Delete(_tempPath, true);
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewWithAllCourses()
        {
            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
            Assert.Equal(5, model.Count);
        }

        [Fact]
        public void Index_IncludesDepartmentData()
        {
            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
            Assert.All(model, c => Assert.NotNull(c.Department));
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
            Assert.NotNull(model.Department);
        }

        #endregion

        #region Create GET Tests

        [Fact]
        public void Create_Get_ReturnsView()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Course>(viewResult.Model);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        #endregion

        #region Create POST Tests

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_Post_ValidCourse_AddsToDatabase()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "Another Course",
                Credits = 4,
                DepartmentID = 2
            };

            _controller.Create(course, null);

            Assert.Equal(6, _context.Courses.Count());
            Assert.NotNull(_context.Courses.Find(8888));
        }

        [Fact]
        public void Create_Post_WithValidImage_SavesFile()
        {
            var course = new Course
            {
                CourseID = 7777,
                Title = "Image Course",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.jpg", 1024);

            _controller.Create(course, mockFile.Object);

            Assert.NotNull(course.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_WithInvalidExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 6666,
                Title = "Bad Image",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.exe", 1024);

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_WithOversizedFile_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 5555,
                Title = "Big Image",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.jpg", 6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 4444, Credits = 3, DepartmentID = 1 };

            var result = _controller.Create(course, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        #endregion

        #region Edit GET Tests

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Edit(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        #endregion

        #region Edit POST Tests

        [Fact]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry Updated",
                Credits = 4,
                DepartmentID = 3
            };
            var tracked = _context.Courses.Find(1050);
            _context.Entry(tracked).State = EntityState.Detached;

            var result = _controller.Edit(course, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_Post_WithValidImage_UpdatesImagePath()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 3
            };
            var tracked = _context.Courses.Find(1050);
            _context.Entry(tracked).State = EntityState.Detached;
            var mockFile = CreateMockFormFile("new_image.png", 2048);

            _controller.Edit(course, mockFile.Object);

            Assert.NotNull(course.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, Credits = 3, DepartmentID = 3 };

            var result = _controller.Edit(course, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        #endregion

        #region Delete GET Tests

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        #endregion

        #region Delete POST Tests

        [Fact]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            var result = _controller.DeleteConfirmed(1050);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesFromDatabase()
        {
            _controller.DeleteConfirmed(1050);

            Assert.Equal(4, _context.Courses.Count());
            Assert.Null(_context.Courses.Find(1050));
        }

        [Fact]
        public void DeleteConfirmed_CourseWithImage_DeletesImageFile()
        {
            // Setup a course with an image file
            var uploadsDir = Path.Combine(_tempPath, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var imagePath = Path.Combine(uploadsDir, "test_image.jpg");
            File.WriteAllText(imagePath, "fake image data");

            var course = _context.Courses.Find(1050);
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
            _context.SaveChanges();

            _controller.DeleteConfirmed(1050);

            Assert.False(File.Exists(imagePath));
        }

        #endregion

        #region Helper Methods

        private static Mock<IFormFile> CreateMockFormFile(string fileName, long length)
        {
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.Length).Returns(length);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));
            return mockFile;
        }

        #endregion
    }
}

