using System;
using System.ComponentModel.DataAnnotations;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class ModelTests
    {
        #region Person / Student / Instructor

        [Fact]
        public void Person_FullName_ConcatenatesLastAndFirst()
        {
            var student = new Student { FirstMidName = "Carson", LastName = "Alexander" };

            Assert.Equal("Alexander, Carson", student.FullName);
        }

        [Fact]
        public void Student_EnrollmentDate_IsRequired()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = default
            };

            var results = ValidateModel(student);
            Assert.Contains(results, v => v.MemberNames.Contains("EnrollmentDate"));
        }

        [Fact]
        public void Student_LastName_IsRequired()
